{"code": "# Fix the extraction for Ocean Power Technologies, Inc.
symbol_to_name = {}
for row in env['data_1']:
    sym = row['Symbol']
    desc = row['Company Description']
    import re
    match = re.search(r'^(.*?)(?:\s+offers\s+|\s+is\s+|\s+provides\s+|\s+aims\s+|\s+seeks\s+|\s+was\s+|\s+specializes\s+|\s+harnesses\s+)', desc, re.IGNORECASE)
    if match:
        name = match.group(1).strip()
    else:
        name = desc.split()[0] # fallback

    # Clean up trailing commas or "based in Canada,"
    name = re.sub(r',\s*based in Canada,?', '', name)
    symbol_to_name[sym] = name

final_results = []
for r in env['data_1']:
    sym = r['Symbol']
    # Find if we have volume for this symbol
    avg_vol = None
    for i in range(2, 24):
        key = f'data_{i}'
        if key in env and env[key] and len(env[key]) > 0 and 'Symbol' in env[key][0]:
            if env[key][0]['Symbol'] == sym:
                avg_vol = env[key][0]['avg_vol']
                break

    if avg_vol is not None:
        name = symbol_to_name.get(sym, sym)
        final_results.append(f"{name}: {avg_vol:.2f}")

env['_answer'] = final_results
print(final_results)
"}
